var createMedicine = async (medeicineData, sellerId) => {
  const result = await prisma.medicines.create({
    data: {
      ...medeicineData,
      Seller_id: sellerId
    },
    include: {
      Category: {
        select: {
          name: true,
          description: true
        }
      },
      Seller: {
        select: {
          name: true,
          email: true,
          id: true
        }
      }
    }
  });
  return result;
};
var getAllMedicine = async (query) => {
  const { name, manufacturer, category, minPrice, maxPrice } = query;
  const filter = {};
  if (name) {
    filter.name = { contains: name, mode: "insensitive" };
  }
  if (manufacturer) {
    filter.manufacturer = { contains: manufacturer, mode: "insensitive" };
  }
  if (category) {
    filter.category = { contains: category, mode: "insensitive" };
  }
  if (minPrice || maxPrice) {
    filter.price = {};
    if (minPrice) filter.price.gte = parseFloat(minPrice);
    if (maxPrice) filter.price.lte = parseFloat(maxPrice);
  }
  const result = await prisma.medicines.findMany({
    where: filter,
    include: {
      Category: {
        select: {
          name: true,
          description: true
        }
      },
      Seller: {
        select: {
          name: true,
          email: true,
          id: true
        }
      }
    }
  });
  return result;
};
var getMedicineById = async (id) => {
  const result = await prisma.medicines.findUnique({
    where: {
      id
    },
    // * if you want to show the catgeory or seller data
    include: {
      Category: true,
      Seller: true
    }
  });
  return result;
};
var updateMedicine = async (id, updateData) => {
  const result = await prisma.medicines.update({
    where: {
      id
    },
    data: updateData
  });
  return result;
};
var deleteMedicine = async (id) => {
  const result = await prisma.medicines.delete({
    where: {
      id
    }
  });
  return result;
};
var medicineServices = {
  createMedicine,
  getAllMedicine,
  getMedicineById,
  updateMedicine,
  deleteMedicine
};

